using System.ComponentModel.DataAnnotations;

namespace sv_290449d866574b3a8d4df6757bf473b3.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding

public class PersonalInfoModel
{
    [Required(ErrorMessage = "Full name is required.")]
    public string FullName { get; set; } = "";

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone number is required.")]
    [Phone(ErrorMessage = "Please enter a valid phone number.")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Address is required.")]
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate ?? DateTime.MinValue, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

public class CoverLetterModel
{
    public string Text { get; set; } = "";
}

@namespace sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex justify-content-between list-unstyled mb-0 position-relative">
        @for (int i = 0; i < Steps.Length; i++)
        {
            var stepIndex = i;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var isFuture = !isCompleted && !isCurrent;

            <li class="step-item flex-fill text-center @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (stepIndex < Steps.Length - 1)
                {
                    <div class="step-line @(isCompleted ? "completed" : "")"></div>
                }
                <button type="button"
                        class="step-circle @(isCurrent ? "active" : isCompleted ? "done" : "pending")"
                        disabled="@(!isCompleted)"
                        @onclick="() => OnStepClicked.InvokeAsync(stepIndex)"
                        aria-label="@(isCompleted ? $"Go back to {Steps[stepIndex]}" : Steps[stepIndex])"
                        aria-current="@(isCurrent ? "step" : null)">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </button>
                <div class="step-label small mt-1 @(isFuture ? "text-muted" : "")">@Steps[stepIndex]</div>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] Steps =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter]
    public EventCallback<int> OnStepClicked { get; set; }
}

.step-item {
    position: relative;
    z-index: 1;
}

.step-line {
    position: absolute;
    top: 17px;
    left: 50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-line.completed {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 2px solid;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
    color: white;
    transition: all 0.2s;
    padding: 0;
}

.step-circle.active {
    background-color: #0d6efd;
    border-color: #0d6efd;
    cursor: default;
}

.step-circle.done {
    background-color: #198754;
    border-color: #198754;
    cursor: pointer;
}

.step-circle.done:disabled {
    opacity: 1;
    pointer-events: auto;
    cursor: pointer;
}

.step-circle.pending {
    background-color: #6c757d;
    border-color: #6c757d;
    cursor: not-allowed;
    opacity: 0.5;
}

.step-label {
    font-weight: 500;
}

.step-item.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

@namespace sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication
@using sv_290449d866574b3a8d4df6757bf473b3.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control @FieldClass(Entry.Company)" @bind="Entry.Company" />
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Company))
                {
                    <div class="invalid-feedback d-block">Company name is required.</div>
                }
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control @FieldClass(Entry.Title)" @bind="Entry.Title" />
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Title))
                {
                    <div class="invalid-feedback d-block">Job title is required.</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control @(ShowErrors && Entry.StartDate is null ? "is-invalid" : "")"
                       @bind="Entry.StartDate" />
                @if (ShowErrors && Entry.StartDate is null)
                {
                    <div class="invalid-feedback d-block">Start date is required.</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" @bind="Entry.IsCurrent" />
                    <label class="form-check-label" for="current-@Index">I currently work here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description <span class="text-danger">*</span></label>
                <textarea class="form-control @FieldClass(Entry.Description)" rows="3" @bind="Entry.Description"></textarea>
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Description))
                {
                    <div class="invalid-feedback d-block">Description is required.</div>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public WorkEntryModel Entry { get; set; } = default!;

    [Parameter]
    public int Index { get; set; }

    [Parameter]
    public bool ShowRemove { get; set; }

    [Parameter]
    public bool ShowErrors { get; set; }

    [Parameter]
    public EventCallback OnRemove { get; set; }

    private string FieldClass(string value) =>
        ShowErrors && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";
}

