<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex justify-content-between list-unstyled mb-0 position-relative">
        @for (int i = 0; i < Steps.Length; i++)
        {
            var stepIndex = i;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var isFuture = !isCompleted && !isCurrent;

            <li class="step-item flex-fill text-center @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (stepIndex < Steps.Length - 1)
                {
                    <div class="step-line @(isCompleted ? "completed" : "")"></div>
                }
                <button type="button"
                        class="step-circle @(isCurrent ? "active" : isCompleted ? "done" : "pending")"
                        disabled="@(!isCompleted)"
                        @onclick="() => OnStepClicked.InvokeAsync(stepIndex)"
                        aria-label="@(isCompleted ? $"Go back to {Steps[stepIndex]}" : Steps[stepIndex])"
                        aria-current="@(isCurrent ? "step" : null)">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </button>
                <div class="step-label small mt-1 @(isFuture ? "text-muted" : "")">@Steps[stepIndex]</div>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] Steps =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter]
    public EventCallback<int> OnStepClicked { get; set; }
}
"}

{"path": "/tmp/sv-290449d866574b3a8d4df6757bf473b3/Components/JobApplication/StepIndicator.razor.css", "file_text": ".step-item {
    position: relative;
    z-index: 1;
}

.step-line {
    position: absolute;
    top: 17px;
    left: 50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-line.completed {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 2px solid;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
    color: white;
    transition: all 0.2s;
    padding: 0;
}

.step-circle.active {
    background-color: #0d6efd;
    border-color: #0d6efd;
    cursor: default;
}

.step-circle.done {
    background-color: #198754;
    border-color: #198754;
    cursor: pointer;
}

.step-circle.done:disabled {
    opacity: 1;
    pointer-events: auto;
    cursor: pointer;
}

.step-circle.pending {
    background-color: #6c757d;
    border-color: #6c757d;
    cursor: not-allowed;
    opacity: 0.5;
}

.step-label {
    font-weight: 500;
}

.step-item.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}
"}

