.step-item {
    position: relative;
    z-index: 1;
}

.step-line {
    position: absolute;
    top: 17px;
    left: 50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-line.completed {
    background-color: #198754;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 2px solid;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    position: relative;
    z-index: 1;
    color: white;
    transition: all 0.2s;
    padding: 0;
}

.step-circle.active {
    background-color: #0d6efd;
    border-color: #0d6efd;
    cursor: default;
}

.step-circle.done {
    background-color: #198754;
    border-color: #198754;
    cursor: pointer;
}

.step-circle.done:disabled {
    opacity: 1;
    pointer-events: auto;
    cursor: pointer;
}

.step-circle.pending {
    background-color: #6c757d;
    border-color: #6c757d;
    cursor: not-allowed;
    opacity: 0.5;
}

.step-label {
    font-weight: 500;
}

.step-item.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

