@namespace sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication
@using sv_290449d866574b3a8d4df6757bf473b3.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control @FieldClass(Entry.Company)" @bind="Entry.Company" />
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Company))
                {
                    <div class="invalid-feedback d-block">Company name is required.</div>
                }
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control @FieldClass(Entry.Title)" @bind="Entry.Title" />
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Title))
                {
                    <div class="invalid-feedback d-block">Job title is required.</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control @(ShowErrors && Entry.StartDate is null ? "is-invalid" : "")"
                       @bind="Entry.StartDate" />
                @if (ShowErrors && Entry.StartDate is null)
                {
                    <div class="invalid-feedback d-block">Start date is required.</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" @bind="Entry.IsCurrent" />
                    <label class="form-check-label" for="current-@Index">I currently work here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description <span class="text-danger">*</span></label>
                <textarea class="form-control @FieldClass(Entry.Description)" rows="3" @bind="Entry.Description"></textarea>
                @if (ShowErrors && string.IsNullOrWhiteSpace(Entry.Description))
                {
                    <div class="invalid-feedback d-block">Description is required.</div>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public WorkEntryModel Entry { get; set; } = default!;

    [Parameter]
    public int Index { get; set; }

    [Parameter]
    public bool ShowRemove { get; set; }

    [Parameter]
    public bool ShowErrors { get; set; }

    [Parameter]
    public EventCallback OnRemove { get; set; }

    private string FieldClass(string value) =>
        ShowErrors && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";
}

