@namespace sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication
@using sv_290449d866574b3a8d4df6757bf473b3.Models
@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

<EditForm Model="Model" OnValidSubmit="HandleNext" FormName="personalInfo">
    <DataAnnotationsValidator />

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <InputText class="form-control" @bind-Value="Model.FullName" />
            <ValidationMessage For="() => Model.FullName" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <InputText class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (emailError is not null)
            {
                <div class="text-danger small mt-1">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <InputText class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>
        <div class="col-12">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <InputTextArea class="form-control" @bind-Value="Model.Address" rows="2" />
            <ValidationMessage For="() => Model.Address" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="submit" class="btn btn-primary" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next →</span>
            }
        </button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        emailError = null;
        isValidating = true;

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address could not be verified. Please use a different email.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@namespace sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication
@using sv_290449d866574b3a8d4df6757bf473b3.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index"
                   ShowRemove="Entries.Count > 1"
                   ShowErrors="showErrors"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

@if (showErrors && !IsValid())
{
    <div class="alert alert-danger">Please fill in all required fields for each position.</div>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired]
    public List<WorkEntryModel> Entries { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    [Parameter]
    public EventCallback OnBack { get; set; }

    private bool showErrors;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private bool IsValid() => Entries.All(e =>
        !string.IsNullOrWhiteSpace(e.Company) &&
        !string.IsNullOrWhiteSpace(e.Title) &&
        e.StartDate is not null &&
        !string.IsNullOrWhiteSpace(e.Description));

    private async Task HandleNext()
    {
        showErrors = true;
        if (IsValid())
            await OnNext.InvokeAsync();
    }
}

