@namespace sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication
@using sv_290449d866574b3a8d4df6757bf473b3.Models

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter <span class="text-danger">*</span></label>
    <textarea class="form-control @(showErrors && string.IsNullOrWhiteSpace(CoverLetter.Text) ? "is-invalid" : "")"
              rows="12"
              maxlength="@MaxLength"
              @bind="CoverLetter.Text"
              @bind:event="oninput"
              placeholder="Tell us why you're a great fit for this position…"></textarea>
    @if (showErrors && string.IsNullOrWhiteSpace(CoverLetter.Text))
    {
        <div class="invalid-feedback">A cover letter is required.</div>
    }
    <div class="form-text text-end">
        <span class="@(CoverLetter.Text.Length > MaxLength ? "text-danger fw-bold" : "")">
            @CoverLetter.Text.Length / @MaxLength characters
        </span>
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired]
    public CoverLetterModel CoverLetter { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    [Parameter]
    public EventCallback OnBack { get; set; }

    private bool showErrors;

    private async Task HandleNext()
    {
        showErrors = true;
        if (!string.IsNullOrWhiteSpace(CoverLetter.Text) && CoverLetter.Text.Length <= MaxLength)
            await OnNext.InvokeAsync();
    }
}

@namespace sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication
@using sv_290449d866574b3a8d4df6757bf473b3.Models

<h4 class="mb-3">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-3">🎉 Application Submitted Successfully!</h5>
        <p class="mb-1">Your application has been received. Your application ID is:</p>
        <p class="fs-3 fw-bold text-success mb-0">#@ApplicationId</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h6 class="mb-0">Personal Information</h6>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row g-2">
                <div class="col-md-6"><strong>Name:</strong> @PersonalInfo.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @PersonalInfo.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @PersonalInfo.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @PersonalInfo.Address</div>
            </div>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h6 class="mb-0">Work History</h6>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @for (int i = 0; i < WorkEntries.Count; i++)
            {
                var entry = WorkEntries[i];
                <div class="@(i < WorkEntries.Count - 1 ? "mb-3 pb-3 border-bottom" : "")">
                    <div class="fw-bold">@entry.Title <span class="fw-normal">at</span> @entry.Company</div>
                    <div class="text-muted small">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </div>
                    <div class="mt-1">@entry.Description</div>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h6 class="mb-0">References</h6>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @for (int i = 0; i < References.Count; i++)
            {
                var reference = References[i];
                <div class="@(i < References.Count - 1 ? "mb-2 pb-2 border-bottom" : "")">
                    <strong>@reference.Name</strong> — @reference.Relationship<br />
                    <span class="text-muted small">@reference.Email · @reference.Phone</span>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h6 class="mb-0">Cover Letter</h6>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter.Text</p>
        </div>
    </div>

    @if (submitError is not null)
    {
        <div class="alert alert-danger">@submitError</div>
    }

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel PersonalInfo { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<WorkEntryModel> WorkEntries { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public CoverLetterModel CoverLetter { get; set; } = default!;

    [Parameter]
    public bool IsSubmitted { get; set; }

    [Parameter]
    public int? ApplicationId { get; set; }

    [Parameter]
    public EventCallback<int> OnEdit { get; set; }

    [Parameter]
    public EventCallback OnBack { get; set; }

    [Parameter]
    public EventCallback OnSubmit { get; set; }

    private bool isSubmitting;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"An error occurred while submitting: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

