@page "/apply"
@using sv_290449d866574b3a8d4df6757bf473b3.Components.JobApplication
@using sv_290449d866574b3a8d4df6757bf473b3.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo" OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="coverLetter" OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep PersonalInfo="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            IsSubmitted="isSubmitted"
                            ApplicationId="applicationId"
                            OnEdit="GoToStep"
                            OnBack="PreviousStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = new();
    private bool isSubmitted;
    private int? applicationId;

    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = [new()];
    private readonly List<ReferenceModel> references = [new(), new()];
    private readonly CoverLetterModel coverLetter = new();

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step))
            currentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter.Text
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

